package mutator

import (
	"github.com/openmeterio/openmeter/openmeter/billing/rating"
	"github.com/openmeterio/openmeter/openmeter/billing/rating/service/rate"
)

type MyCap struct{}

var _ PostCalculationMutator = (*MyCap)(nil)

func (m *MyCap) Mutate(i rate.PricerCalculateInput, lines rating.DetailedLines) (rating.DetailedLines, error) {
	if !i.IsLastInPeriod() {
		return lines, nil
	}
	return lines, nil
}

package rate

import (
	"github.com/openmeterio/openmeter/openmeter/billing/rating"
	"github.com/openmeterio/openmeter/openmeter/productcatalog"
)

type Stepped struct {
	ProgressiveBillingMeteredPricer
}

var _ Pricer = (*Stepped)(nil)

func (p Stepped) GenerateDetailedLines(l PricerCalculateInput) (rating.DetailedLines, error) {
	usage, err := l.GetUsage()
	if err != nil {
		return nil, err
	}
	_ = usage
	return nil, nil
}
